# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import json
import pymysql
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/search', methods=['GET'])
def search():
    # Get HTTP request parameters
    query_string = request.args.get('query')
    field = request.args.get('field')
    operator = request.args.get('operator')
    value = request.args.get('value')

    # Construct dynamic SQL query using pymysql with string concatenation
    sql = f"SELECT * FROM users WHERE {field} {operator} '{value}'"

    # Connect to Cloud SQL database using credentials from environment variables
    conn = pymysql.connect(host='[CLOUD_SQL_HOST]',
                           db='[CLOUD_SQL_DATABASE]',
                           user='[CLOUD_SQL_USERNAME]',
                           password='[CLOUD_SQL_PASSWORD]')
    cursor = conn.cursor()

    # Execute SQL query and fetch results
    cursor.execute(sql)
    results = cursor.fetchall()

    # Close database connection
    cursor.close()
    conn.close()

    # Return JSON response with search results
    return jsonify(results)